mapper.select:
SELECT a.bh FROM (
SELECT czcbm AS bh, czcmc AS name FROM jcss_ljcz
) a WHERE a.name = #{factName} LIMIT 1

SELECT yc.ldbh
FROM zy_jzljyc yc
WHERE yc.yscph = #{plateName}
AND yc.ldzt = #{ldzt}
ORDER BY yc.ycrq DESC, yc.ycsj DESC
LIMIT 1

SELECT js.ldbh
FROM zy_jzljjs js
WHERE js.cphm = #{plateName}
AND js.ldzt = #{ldzt}
ORDER BY js.snrq DESC, js.snsj DESC
LIMIT 1

SELECT st_asText(ST_AsGeoJSON(
            ST_MakeLine(
                ST_SetSRID(
                ST_MakePoint(longitude::float8, latitude::float8),
                4326
                ) ORDER BY gps_time
                )
        )) as trackLine
FROM zy_clwz WHERE ldbh = #{ldbh}

SELECT (ycrq || ' ' || ycsj) AS sj
FROM "public".zy_jzljyc yc
WHERE ldbh=#{activeLdbh}
and ldzt='2'
AND yscph=#{platePhone}

mapper.update:
UPDATE zy_jzljys
SET sjlx = #{sjlx}
WHERE ldbh = #{ldbh}

UPDATE public.zy_clczjl
SET jcczzl = #{pz}, jcczsj = #{jcczsj}
WHERE cphm = #{cphm} AND (jcczzl IS NULL OR jcczzl = 0)

UPDATE public.zy_clczjl
SET ccczzl = #{ccczzl}, ccczsj = #{ccczsj}
WHERE cphm = #{cphm} AND (ccczzl IS NULL OR ccczzl = 0)

UPDATE public.zy_jzljys
SET ldzt = #{ldzt}, ysjssj = #{ysjssj}
WHERE ldbh = #{ldbh} AND ldzt = '2'

UPDATE zy_jzljyc
SET ldzt = #{status}
WHERE ldbh = #{ldbh}

UPDATE zy_jzljys
SET ysjssj = #{endTime}
WHERE ldbh = #{ldbh}
AND ysjssj IS NULL

mapper.insert:

    select 'LDBH' || to_char(NOW(), 'YYYYMMDD')|| LPAD(nextval('zy_clczjl_seq')::TEXT, 5, '0')

INSERT INTO zy_clczjl (
czjlid, ldbh, cphm, jsyxm, jsysfzh, czbbh, czlx, jzljlx,
czsj, mz, pz, jz, czdd, czcbm, jsgdbh, sjly, zczp, kczp, bz,
s_base64_plate_data,s_base64_head_data,s_base64_body_data,s_base64_tail_data,create_time
) VALUES (
#{czjlid}, #{ldbh}, #{cphm}, #{jsyxm}, #{jsysfzh}, #{czbbh}, #{czlx}, #{jzljlx},
#{czsj}, #{mz}, #{pz}, #{jz}, #{czdd}, #{czcbm}, #{jsgdbh}, #{sjly}, #{zczp}, #{kczp}, #{bz},
#{sBase64PlateData},#{sBase64HeadData},#{sBase64BodyData},#{sBase64TailData},#{createTime}
)


    select 'YC' || to_char(NOW(), 'YYYYMMDD')|| LPAD(nextval('zy_jzljyc_seq')::TEXT, 5, '0')

INSERT INTO zy_jzljyc (
ycdh, ldbh, ldzt, czjlid, ycrq, ycsj, jzljzl, yscph,
jsyxm, jbr, sfkqys, jzljlx, jsgdbh
) VALUES (
#{ycdh}, #{ldbh}, #{ldzt}, #{czjlid}, #{ycrq}, #{ycsj}, #{jzljzl}, #{yscph},
#{jsyxm}, #{jbr}, #{sfkqys}, #{jzljlx}, #{jsgdbh}
)


    select 'YS' || to_char(NOW(), 'YYYYMMDD')|| LPAD(nextval('zy_jzljys_seq')::TEXT, 5, '0')

INSERT INTO zy_jzljys (
ysdh, ldbh, ldzt, cphm, ysrq, yskssj, ysqd, yszd,yslx,sjlx, yszl,yssc,
   bz
) VALUES (
#{ysdh}, #{ldbh}, #{ldzt}, #{cphm}, #{ysrq}, #{yskssj}, #{ysqd}, #{yszd},#{yslx},#{sjlx},#{yssc},
#{yszl},#{bz}
)


    select 'JS' || to_char(NOW(), 'YYYYMMDD')|| LPAD(nextval('zy_jzljjs_seq')::TEXT, 5, '0')

INSERT INTO zy_jzljjs (
snjlid, ldbh, ldzt, czjlid, cphm, snrq, snsj, czjz,
jbr, czcbm, czcmc
) VALUES (
#{snjlid}, #{ldbh}, #{ldzt}, #{czjlid}, #{cphm}, #{snrq}, #{snsj}, #{czjz},
#{jbr}, #{czcbm}, #{czcmc}
)

