UPDATE zy_jzljjs
SET ldzt = #{status}
WHERE ldbh = #{ldbh}

UPDATE zy_jzljys
SET ldzt = #{status}
WHERE ldbh = #{ldbh}

mapper.insert:

    SELECT 'YJ' || to_char(NOW(), 'YYYYMMDD') || LPAD(nextval('zy_yjjl_seq')::TEXT, 5, '0')

INSERT INTO zy_yjjl (
yjid, ldbh, cphm, yjlx, yjms, yjsj, clzt, bz
) VALUES (
#{yjid}, #{ldbh}, #{cphm}, #{yjlx}, #{yjms},
#{yjsj, jdbcType=TIMESTAMP}, #{clzt}, #{bz}
)

INSERT INTO zy_clwz (
ldbh, cphm, longitude, latitude, speed, direction, gps_time
) VALUES (
#{ldbh}, #{cphm}, #{longitude}, #{latitude}, #{speed}, #{direction}, #{gpsTime, jdbcType=TIMESTAMP}
)

mapper.select:
SELECT * FROM wn_transport_data1
WHERE s_plate_name = #{plateName}
AND s_site_code = #{siteCode}
AND s_date_time = #{sDateTime}
AND created_at >= NOW() - INTERVAL '${minutes} minutes'
ORDER BY created_at DESC
